const rawJson = $input.first().json;

const ollamaResponse = rawJson.ollama_response || rawJson;

let generatedBody =
  ollamaResponse.message?.content ||
  ollamaResponse.response ||
  ollamaResponse.text ||
  ollamaResponse.output ||
  ollamaResponse.content ||
  "";

if (!generatedBody) {
  throw new Error(
    "No cover letter body found from Ollama output. Output keys: " +
      Object.keys(ollamaResponse).join(", ")
  );
}

// Clean model output
generatedBody = String(generatedBody)
  .replace(/```latex/g, "")
  .replace(/```tex/g, "")
  .replace(/```/g, "")
  .replace(/:contentReference\[[^\]]*\]\{[^}]*\}/g, "")
  .replace(/\\documentclass[\s\S]*?\\begin\{document\}/g, "")
  .replace(/\\end\{document\}/g, "")
  .trim();

// Remove accidental greeting/signature if model includes it
generatedBody = generatedBody
  .replace(/^\\textbf\{Hello,\}\s*/i, "")
  .replace(/^Hello,?\s*/i, "")
  .replace(/\\noindent\s*Sincerely,\\\\[\s\S]*$/i, "")
  .replace(/Sincerely,\\\\[\s\S]*$/i, "")
  .replace(/Sincerely,[\s\S]*$/i, "")
  .trim();

// Get original form data directly from Form Trigger
const formData = $("Form Trigger").first().json;

// Try multiple possible field names, because n8n sometimes stores labels differently
const companyRaw =
  rawJson.company_name ||
  formData.company_name ||
  formData.companyName ||
  formData["Company Name"] ||
  formData["company name"] ||
  formData.Company ||
  formData.company ||
  "company";

const roleRaw =
  rawJson.role_title ||
  formData.role_title ||
  formData.roleTitle ||
  formData["Role Title"] ||
  formData["role title"] ||
  formData.Role ||
  formData.role ||
  "role";

