`;

const updatedLatex = latexTemplate.replace(
  "OLD BODY PLACEHOLDER",
  generatedBody
);

function slugify(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/&/g, "and")
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 60);
}

const company = slugify(companyRaw) || "company";
const role = slugify(roleRaw) || "role";

const baseName = `cover_letter_${company}_${role}`;
const workDir = `/home/node/.n8n-files/${baseName}_${Date.now()}`;

const latexBase64 = Buffer.from(updatedLatex, "utf8").toString("base64");

return [
  {
    json: {
      company_raw: companyRaw,
      role_raw: roleRaw,
      generated_body: generatedBody,
      updated_latex: updatedLatex,
      latex_base64: latexBase64,
      work_dir: workDir,
      tex_path: `${workDir}/${baseName}.tex`,
      pdf_path: `${workDir}/${baseName}.pdf`,
      tex_file_name: `${baseName}.tex`,
      pdf_file_name: `${baseName}.pdf`
    }
  }
];

const input = $input.first().json;

const companyName = input.company_name || "";
const roleTitle = input.role_title || "";
const jobDescription = input.job_description || "";
const customPrompt = input.custom_prompt || "";
const resumeLatex = input.resume_latex || "";
const extraNotes = input.extra_notes || "";

const backgroundSummary = resumeLatex.trim()
  ? ""
  : `Candidate background summary:
- Master of Applied Computer Science from Dalhousie University.
- Full-stack/software developer background with React, Next.js, JavaScript, TypeScript, Python, Django, Node.js, Express, REST APIs, SQL, PostgreSQL, MongoDB, Docker, CI/CD, AWS, GCP, and Kubernetes.
- Persuasive Computing Lab experience building full-stack features with Django, REST APIs, Next.js, React, Redux, WebSockets, dashboards, backend services, and data-driven workflows.
- Project experience with cloud deployments, containerized applications, data pipelines, analytical dashboards, and debugging across the stack.
- Current OPOR/Nova Scotia Health experience includes dashboards, operational tracking, deployment readiness, downtime planning, reporting, and working with cross-functional teams.`;

const prompt = `Write ONLY the body section of a LaTeX cover letter.

Return only the text that goes between \\textbf{Hello,} and Sincerely.
Do not include Hello.
Do not include Sincerely.
Do not return full LaTeX document.
Do not use markdown.
Do not explain.

COMPANY:
${companyName}

ROLE:
${roleTitle}

JOB DESCRIPTION:
${jobDescription}

USER INSTRUCTIONS:
${customPrompt}

EXTRA NOTES:
${extraNotes}

RESUME SOURCE:
${resumeLatex}

${backgroundSummary}

Rules:
- Use resume/source as truth. Do not invent experience, tools, dates, numbers, or achievements.
- Exactly  3 short paragraphs.
- Under 500 words.
- Please do not use em dashes.
- Human, natural, confident.
- Open strong and creative sound like a human.
- No generic opening like "I am excited to apply".
- No begging tone.
- No em dash.
- Use simple language.
- Use \\textbf{} for important matching skills/tools only.
- Escape special LaTeX characters in normal text.
- Do not include citations, references, links, footnotes, or contentReference text.
- End naturally before the signature.`;

return [
  {
    json: {
      company_name: companyName,
      role_title: roleTitle,
      job_description: jobDescription,
      custom_prompt: customPrompt,
      extra_notes: extraNotes,
      ollama_body: {
        model: "qwen2.5:7b",
        messages: [
          {
            role: "user",
            content: prompt
          }
        ],
        stream: false,
        options: {
          temperature: 0.3,
          num_predict: 900,
          top_p: 0.9,
          repeat_penalty: 1.1,
          num_ctx: 8192
        }
      }
    }
  }
];

